import SwiftUI

struct NavigationDemo: View {
    var body: some View {
        NavigationStack {
            List {
                Section("Getting Started") {
                    NavigationLink("Introduction to Swift") {
                        LessonDetail(title: "Introduction to Swift")
                    }
                    NavigationLink("Variables and Constants") {
                        LessonDetail(title: "Variables and Constants")
                    }
                }

                Section("Core Concepts") {
                    NavigationLink("Control Flow") {
                        LessonDetail(title: "Control Flow")
                    }
                    NavigationLink("Functions") {
                        LessonDetail(title: "Functions")
                    }
                }
            }
            .navigationTitle("Swift Fundamentals")
            .toolbar {
                ToolbarItem(placement: .primaryAction) {
                    Button(action: {}) {
                        Image(systemName: "bookmark")
                    }
                }
            }
        }
    }
}

struct LessonDetail: View {
    let title: String

    var body: some View {
        VStack(spacing: 20) {
            Image(systemName: "doc.text.fill")
                .font(.system(size: 60))
                .foregroundColor(.blue)

            Text(title)
                .font(.title)
                .fontWeight(.bold)

            Text("Lesson content goes here...")
                .foregroundColor(.secondary)
        }
        .padding()
        .navigationTitle(title)
    }
}

